// src/pages/HomeScreen.js
import React from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TouchableOpacity,
  ScrollView,
} from "react-native";
import { useNavigation } from "@react-navigation/native";

// ✅ From src/pages -> root/assets = ../../assets
const taxiImg = require("../../assets/taxi.png");
const cityLogo = require("../../assets/urban.png");
const tickCircle = require("../../assets/tickcircle.png");
const shieldLock = require("../../assets/shieldd.png");

export default function HomeScreen() {
  const navigation = useNavigation();

  // ✅ Static for now (you can wire it later to API/Storage)
  const plateNumber = "CE696KO";

  const goToOfficialControl = () => {
    // ✅ IMPORTANT: this route name must exist in your navigator
    // If your screen is named differently, change it here.
    navigation.navigate("official-control");
  };

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
      >
        <View style={styles.screen}>
          <View style={styles.heroWrap}>
            <View style={styles.faintCircle} />
            <Image source={taxiImg} style={styles.taxi} resizeMode="contain" />
            <Image source={tickCircle} style={styles.bigPin} resizeMode="contain" />
          </View>

          <View style={styles.statusRow}>
            <Image source={tickCircle} style={styles.smallTick} resizeMode="contain" />
            <Text style={styles.statusText}>Vérifié</Text>
          </View>

          <View style={styles.plateWrap}>
            <Text style={styles.plateText}>{plateNumber}</Text>
          </View>

          <TouchableOpacity
            activeOpacity={0.9}
            style={styles.officialBtn}
            onPress={goToOfficialControl}
          >
            <Image source={shieldLock} style={styles.btnIcon} resizeMode="contain" />
            <Text style={styles.btnText}>Contrôle officiel</Text>
          </TouchableOpacity>

          <View style={styles.logoWrap}>
            <Image source={cityLogo} style={styles.logo} resizeMode="contain" />
            <Text style={styles.logoText}>
              Communauté Urbaine{"\n"}de Yaoundé
            </Text>
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#F5F6FA" },
  scroll: { paddingBottom: 24 },
  screen: { paddingTop: 18, paddingHorizontal: 18, alignItems: "center" },

  heroWrap: {
    width: "100%",
    height: 290,
    alignItems: "center",
    justifyContent: "center",
    position: "relative",
    marginTop: 6,
  },
  faintCircle: {
    position: "absolute",
    width: 280,
    height: 280,
    borderRadius: 140,
    backgroundColor: "#E9EEF6",
    opacity: 0.55,
  },
  taxi: { width: "92%", height: 210, zIndex: 2 },
  bigPin: {
    position: "absolute",
    right: 8,
    top: 26,
    width: 120,
    height: 120,
    zIndex: 3,
  },

  statusRow: { flexDirection: "row", alignItems: "center", marginTop: 6, gap: 10 },
  smallTick: { width: 44, height: 44 },
  statusText: { fontSize: 34, fontWeight: "800", color: "#2F7D3A", letterSpacing: 0.2 },

  plateWrap: {
    marginTop: 14,
    paddingHorizontal: 22,
    paddingVertical: 10,
    borderRadius: 12,
    borderWidth: 3,
    borderColor: "#2F7D3A",
    backgroundColor: "#FFFFFF",
  },
  plateText: { fontSize: 42, fontWeight: "900", letterSpacing: 1, color: "#111827" },

  officialBtn: {
    marginTop: 18,
    width: "82%",
    height: 56,
    backgroundColor: "#0F3C2F",
    borderRadius: 14,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    gap: 10,
    shadowColor: "#000",
    shadowOpacity: 0.18,
    shadowRadius: 12,
    shadowOffset: { width: 0, height: 10 },
    elevation: 6,
    borderWidth: 1,
    borderColor: "rgba(255,255,255,0.18)",
  },
  btnIcon: { width: 26, height: 26 },
  btnText: { color: "#FFFFFF", fontSize: 20, fontWeight: "800", letterSpacing: 0.2 },

  logoWrap: { marginTop: 22, alignItems: "center" },
  logo: { width: 120, height: 120 },
  logoText: {
    marginTop: 10,
    textAlign: "center",
    fontSize: 22,
    fontWeight: "700",
    color: "#1F2937",
    lineHeight: 28,
  },
});
